mapper.update:
update col_kb

    kbname=#{kbName},
    colname=#{colName},
    type=#{type, typeHandler=top.emilejones.hhu.knowledge.handler.KnowledgeCatalogTypeHandler},
    isdelete=#{isDelete}
    createtime=#{createTime},
    permission=#{permission}

where kb_id=#{kbId}

update collection_document set isdelete=0
kb_id=#{knowledgeCatalogId} and document_id in
#{knowledgeDocument}
